"""Linear models: LinearRegression, LogisticRegression, Ridge, Lasso."""
import numpy as np
from sklearn.base import BaseEstimator, RegressorMixin, ClassifierMixin


class LinearRegression(BaseEstimator, RegressorMixin):
    def __init__(self, *, fit_intercept=True, copy_X=True, n_jobs=None,
                 positive=False):
        self.fit_intercept = fit_intercept
        self.copy_X = copy_X
        self.n_jobs = n_jobs
        self.positive = positive
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if self.fit_intercept:
            X = np.column_stack([np.ones(X.shape[0]), X])
        w = np.linalg.lstsq(X, y, rcond=None)[0]
        if self.fit_intercept:
            self.intercept_ = float(w[0])
            self.coef_ = w[1:]
        else:
            self.coef_ = w
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class Ridge(BaseEstimator, RegressorMixin):
    def __init__(self, alpha=1.0, *, fit_intercept=True, copy_X=True,
                 max_iter=None, tol=1e-4, solver='auto', positive=False,
                 random_state=None):
        self.alpha = alpha
        self.fit_intercept = fit_intercept
        self.copy_X = copy_X
        self.max_iter = max_iter
        self.tol = tol
        self.solver = solver
        self.positive = positive
        self.random_state = random_state
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if self.fit_intercept:
            self.intercept_ = float(np.mean(y))
            y = y - self.intercept_
        n_features = X.shape[1]
        self.coef_ = np.linalg.solve(X.T @ X + self.alpha * np.eye(n_features), X.T @ y)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class Lasso(BaseEstimator, RegressorMixin):
    """Lasso via coordinate descent."""
    def __init__(self, alpha=1.0, *, fit_intercept=True, precompute=False,
                 copy_X=True, max_iter=1000, tol=1e-4, warm_start=False,
                 positive=False, random_state=None, selection='cyclic'):
        self.alpha = alpha
        self.fit_intercept = fit_intercept
        self.precompute = precompute
        self.copy_X = copy_X
        self.max_iter = max_iter
        self.tol = tol
        self.warm_start = warm_start
        self.positive = positive
        self.random_state = random_state
        self.selection = selection
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            self.intercept_ = float(np.mean(y))
            y = y - self.intercept_
        w = np.zeros(p)
        for _ in range(self.max_iter):
            w_old = w.copy()
            for j in range(p):
                r = y - X @ w + X[:, j] * w[j]
                rho = X[:, j] @ r
                z = X[:, j] @ X[:, j]
                if z == 0:
                    w[j] = 0
                else:
                    w[j] = np.sign(rho) * max(abs(rho) - self.alpha * n / 2, 0) / z
            if np.max(np.abs(w - w_old)) < self.tol:
                break
        self.coef_ = w
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class LogisticRegression(BaseEstimator, ClassifierMixin):
    """Binary/multiclass logistic regression via gradient descent."""
    def __init__(self, penalty='l2', *, dual=False, tol=1e-4, C=1.0,
                 fit_intercept=True, intercept_scaling=1, class_weight=None,
                 random_state=None, solver='lbfgs', max_iter=200,
                 multi_class='auto', verbose=0, warm_start=False,
                 n_jobs=None, l1_ratio=None, lr=0.1):
        self.penalty = penalty
        self.dual = dual
        self.tol = tol
        self.C = C
        self.fit_intercept = fit_intercept
        self.intercept_scaling = intercept_scaling
        self.class_weight = class_weight
        self.random_state = random_state
        self.solver = solver
        self.max_iter = max_iter
        self.multi_class = multi_class
        self.verbose = verbose
        self.warm_start = warm_start
        self.n_jobs = n_jobs
        self.l1_ratio = l1_ratio
        self.lr = lr
        self.coef_ = None
        self.intercept_ = None
        self.classes_ = None

    def _sigmoid(self, z):
        return 1.0 / (1.0 + np.exp(-np.clip(z, -500, 500)))

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        n, p = X.shape
        if len(self.classes_) == 2:
            y_bin = (y == self.classes_[1]).astype(float)
            w = np.zeros(p)
            b = 0.0
            for _ in range(self.max_iter):
                z = X @ w + b
                h = self._sigmoid(z)
                grad_w = (X.T @ (h - y_bin)) / n + w / (self.C * n)
                grad_b = np.mean(h - y_bin)
                w -= self.lr * grad_w
                b -= self.lr * grad_b
            self.coef_ = w.reshape(1, -1)
            self.intercept_ = np.array([b])
        else:
            k = len(self.classes_)
            W = np.zeros((k, p))
            B = np.zeros(k)
            for _ in range(self.max_iter):
                scores = X @ W.T + B
                exp_s = np.exp(scores - np.max(scores, axis=1, keepdims=True))
                probs = exp_s / exp_s.sum(axis=1, keepdims=True)
                for c in range(k):
                    y_c = (y == self.classes_[c]).astype(float)
                    diff = probs[:, c] - y_c
                    W[c] -= self.lr * (X.T @ diff / n + W[c] / (self.C * n))
                    B[c] -= self.lr * np.mean(diff)
            self.coef_ = W
            self.intercept_ = B
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if len(self.classes_) == 2:
            proba = self._sigmoid(X @ self.coef_[0] + self.intercept_[0])
            return np.where(proba >= 0.5, self.classes_[1], self.classes_[0])
        scores = X @ self.coef_.T + self.intercept_
        return self.classes_[np.argmax(scores, axis=1)]

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if len(self.classes_) == 2:
            p1 = self._sigmoid(X @ self.coef_[0] + self.intercept_[0])
            return np.column_stack([1 - p1, p1])
        scores = X @ self.coef_.T + self.intercept_
        exp_s = np.exp(scores - np.max(scores, axis=1, keepdims=True))
        return exp_s / exp_s.sum(axis=1, keepdims=True)


class ElasticNet(BaseEstimator, RegressorMixin):
    """ElasticNet: L1+L2 regularised regression via coordinate descent."""
    def __init__(self, alpha=1.0, *, l1_ratio=0.5, fit_intercept=True,
                 precompute=False, max_iter=1000, copy_X=True, tol=1e-4,
                 warm_start=False, positive=False, random_state=None,
                 selection='cyclic'):
        self.alpha = alpha
        self.l1_ratio = l1_ratio
        self.fit_intercept = fit_intercept
        self.precompute = precompute
        self.max_iter = max_iter
        self.copy_X = copy_X
        self.tol = tol
        self.warm_start = warm_start
        self.positive = positive
        self.random_state = random_state
        self.selection = selection
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            self.intercept_ = float(np.mean(y))
            y = y - self.intercept_
        w = np.zeros(p)
        l1_pen = self.alpha * self.l1_ratio * n / 2.0
        l2_pen = self.alpha * (1.0 - self.l1_ratio) * n
        for _ in range(self.max_iter):
            w_old = w.copy()
            indices = np.arange(p)
            if self.selection == 'random':
                rng = np.random.RandomState(self.random_state)
                rng.shuffle(indices)
            for j in indices:
                r = y - X @ w + X[:, j] * w[j]
                rho = X[:, j] @ r
                z = X[:, j] @ X[:, j] + l2_pen
                if z == 0:
                    w[j] = 0.0
                else:
                    w[j] = np.sign(rho) * max(abs(rho) - l1_pen, 0.0) / z
                if self.positive and w[j] < 0:
                    w[j] = 0.0
            if np.max(np.abs(w - w_old)) < self.tol:
                break
        self.coef_ = w
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class SGDClassifier(BaseEstimator, ClassifierMixin):
    """Stochastic Gradient Descent classifier."""
    def __init__(self, loss='hinge', *, penalty='l2', alpha=0.0001,
                 l1_ratio=0.15, fit_intercept=True, max_iter=1000, tol=1e-3,
                 shuffle=True, verbose=0, epsilon=0.1, n_jobs=None,
                 random_state=None, learning_rate='optimal', eta0=0.0,
                 power_t=0.5, early_stopping=False, validation_fraction=0.1,
                 n_iter_no_change=5, class_weight=None, warm_start=False,
                 average=False):
        self.loss = loss
        self.penalty = penalty
        self.alpha = alpha
        self.l1_ratio = l1_ratio
        self.fit_intercept = fit_intercept
        self.max_iter = max_iter
        self.tol = tol
        self.shuffle = shuffle
        self.verbose = verbose
        self.epsilon = epsilon
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.learning_rate = learning_rate
        self.eta0 = eta0
        self.power_t = power_t
        self.early_stopping = early_stopping
        self.validation_fraction = validation_fraction
        self.n_iter_no_change = n_iter_no_change
        self.class_weight = class_weight
        self.warm_start = warm_start
        self.average = average
        self.coef_ = None
        self.intercept_ = None
        self.classes_ = None

    def _get_eta(self, t):
        if self.learning_rate == 'constant':
            return self.eta0
        elif self.learning_rate == 'invscaling':
            return self.eta0 / (t ** self.power_t)
        else:  # optimal
            return 1.0 / (self.alpha * (t + 1000))

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        n, p = X.shape
        rng = np.random.RandomState(self.random_state)
        if len(self.classes_) == 2:
            y_bin = np.where(y == self.classes_[1], 1.0, -1.0)
            w = np.zeros(p)
            b = 0.0
            t = 1.0
            for _ in range(self.max_iter):
                idx = np.arange(n)
                if self.shuffle:
                    rng.shuffle(idx)
                for i in idx:
                    eta = self._get_eta(t)
                    margin = y_bin[i] * (X[i] @ w + b)
                    if self.loss == 'hinge':
                        if margin < 1.0:
                            w *= (1 - eta * self.alpha)
                            w += eta * y_bin[i] * X[i]
                            if self.fit_intercept:
                                b += eta * y_bin[i]
                        else:
                            w *= (1 - eta * self.alpha)
                    elif self.loss == 'log_loss':
                        sig = 1.0 / (1.0 + np.exp(-np.clip(margin, -500, 500)))
                        w *= (1 - eta * self.alpha)
                        w += eta * y_bin[i] * (1 - sig) * X[i]
                        if self.fit_intercept:
                            b += eta * y_bin[i] * (1 - sig)
                    else:  # modified_huber
                        if margin < -1.0:
                            w *= (1 - eta * self.alpha)
                            w += eta * 4 * y_bin[i] * X[i]
                            if self.fit_intercept:
                                b += eta * 4 * y_bin[i]
                        elif margin < 1.0:
                            w *= (1 - eta * self.alpha)
                            w += eta * 2 * (1 - margin) * y_bin[i] * X[i]
                            if self.fit_intercept:
                                b += eta * 2 * (1 - margin) * y_bin[i]
                        else:
                            w *= (1 - eta * self.alpha)
                    t += 1
            self.coef_ = w.reshape(1, -1)
            self.intercept_ = np.array([b])
        else:
            k = len(self.classes_)
            W = np.zeros((k, p))
            B = np.zeros(k)
            t = 1.0
            for _ in range(self.max_iter):
                idx = np.arange(n)
                if self.shuffle:
                    rng.shuffle(idx)
                for i in idx:
                    eta = self._get_eta(t)
                    scores = X[i] @ W.T + B
                    true_c = np.where(self.classes_ == y[i])[0][0]
                    for c in range(k):
                        target = 1.0 if c == true_c else -1.0
                        margin = target * scores[c]
                        if margin < 1.0:
                            W[c] *= (1 - eta * self.alpha)
                            W[c] += eta * target * X[i]
                            if self.fit_intercept:
                                B[c] += eta * target
                        else:
                            W[c] *= (1 - eta * self.alpha)
                    t += 1
            self.coef_ = W
            self.intercept_ = B
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if len(self.classes_) == 2:
            scores = X @ self.coef_[0] + self.intercept_[0]
            return np.where(scores >= 0, self.classes_[1], self.classes_[0])
        scores = X @ self.coef_.T + self.intercept_
        return self.classes_[np.argmax(scores, axis=1)]

    def decision_function(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if len(self.classes_) == 2:
            return X @ self.coef_[0] + self.intercept_[0]
        return X @ self.coef_.T + self.intercept_


class SGDRegressor(BaseEstimator, RegressorMixin):
    """Stochastic Gradient Descent regressor."""
    def __init__(self, loss='squared_error', *, penalty='l2', alpha=0.0001,
                 l1_ratio=0.15, fit_intercept=True, max_iter=1000, tol=1e-3,
                 shuffle=True, verbose=0, epsilon=0.1, random_state=None,
                 learning_rate='invscaling', eta0=0.01, power_t=0.25,
                 early_stopping=False, validation_fraction=0.1,
                 n_iter_no_change=5, warm_start=False, average=False):
        self.loss = loss
        self.penalty = penalty
        self.alpha = alpha
        self.l1_ratio = l1_ratio
        self.fit_intercept = fit_intercept
        self.max_iter = max_iter
        self.tol = tol
        self.shuffle = shuffle
        self.verbose = verbose
        self.epsilon = epsilon
        self.random_state = random_state
        self.learning_rate = learning_rate
        self.eta0 = eta0
        self.power_t = power_t
        self.early_stopping = early_stopping
        self.validation_fraction = validation_fraction
        self.n_iter_no_change = n_iter_no_change
        self.warm_start = warm_start
        self.average = average
        self.coef_ = None
        self.intercept_ = np.array([0.0])

    def _get_eta(self, t):
        if self.learning_rate == 'constant':
            return self.eta0
        elif self.learning_rate == 'invscaling':
            return self.eta0 / (t ** self.power_t)
        else:
            return 1.0 / (self.alpha * (t + 1000))

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        rng = np.random.RandomState(self.random_state)
        w = np.zeros(p)
        b = 0.0
        t = 1.0
        for _ in range(self.max_iter):
            idx = np.arange(n)
            if self.shuffle:
                rng.shuffle(idx)
            for i in idx:
                eta = self._get_eta(t)
                pred = X[i] @ w + b
                err = pred - y[i]
                if self.loss == 'squared_error':
                    grad = err
                elif self.loss == 'huber':
                    if abs(err) <= self.epsilon:
                        grad = err
                    else:
                        grad = self.epsilon * np.sign(err)
                elif self.loss == 'epsilon_insensitive':
                    if abs(err) <= self.epsilon:
                        grad = 0.0
                    else:
                        grad = np.sign(err)
                else:
                    grad = err
                w *= (1 - eta * self.alpha)
                w -= eta * grad * X[i]
                if self.fit_intercept:
                    b -= eta * grad
                t += 1
        self.coef_ = w
        self.intercept_ = np.array([b])
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_[0]


class RidgeClassifier(BaseEstimator, ClassifierMixin):
    """Ridge regression applied to indicator matrix for classification."""
    def __init__(self, alpha=1.0, *, fit_intercept=True, copy_X=True,
                 max_iter=None, tol=1e-4, class_weight=None, solver='auto'):
        self.alpha = alpha
        self.fit_intercept = fit_intercept
        self.copy_X = copy_X
        self.max_iter = max_iter
        self.tol = tol
        self.class_weight = class_weight
        self.solver = solver
        self.coef_ = None
        self.intercept_ = None
        self.classes_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        k = len(self.classes_)
        n, p = X.shape
        # Build indicator matrix
        Y = np.zeros((n, k))
        for c_idx, c in enumerate(self.classes_):
            Y[y == c, c_idx] = 1.0
        if self.fit_intercept:
            Y_mean = Y.mean(axis=0)
            X_mean = X.mean(axis=0)
            Y_c = Y - Y_mean
            X_c = X - X_mean
        else:
            Y_c = Y
            X_c = X
        A = X_c.T @ X_c + self.alpha * np.eye(p)
        B = X_c.T @ Y_c
        W = np.linalg.solve(A, B)  # (p, k)
        self.coef_ = W.T  # (k, p)
        if self.fit_intercept:
            self.intercept_ = Y_mean - X_mean @ W
        else:
            self.intercept_ = np.zeros(k)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        scores = X @ self.coef_.T + self.intercept_
        return self.classes_[np.argmax(scores, axis=1)]

    def decision_function(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_.T + self.intercept_


class Perceptron(BaseEstimator, ClassifierMixin):
    """Perceptron classifier (wrapper around SGD with hinge loss)."""
    def __init__(self, *, penalty=None, alpha=0.0001, l1_ratio=0.15,
                 fit_intercept=True, max_iter=1000, tol=1e-3, shuffle=True,
                 verbose=0, eta0=1.0, n_jobs=None, random_state=0,
                 early_stopping=False, validation_fraction=0.1,
                 n_iter_no_change=5, class_weight=None, warm_start=False):
        self.penalty = penalty
        self.alpha = alpha
        self.l1_ratio = l1_ratio
        self.fit_intercept = fit_intercept
        self.max_iter = max_iter
        self.tol = tol
        self.shuffle = shuffle
        self.verbose = verbose
        self.eta0 = eta0
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.early_stopping = early_stopping
        self.validation_fraction = validation_fraction
        self.n_iter_no_change = n_iter_no_change
        self.class_weight = class_weight
        self.warm_start = warm_start
        self._sgd = None
        self.coef_ = None
        self.intercept_ = None
        self.classes_ = None

    def fit(self, X, y):
        pen = self.penalty if self.penalty is not None else 'l2'
        alph = self.alpha if self.penalty is not None else 0.0
        self._sgd = SGDClassifier(
            loss='hinge', penalty=pen, alpha=alph,
            l1_ratio=self.l1_ratio, fit_intercept=self.fit_intercept,
            max_iter=self.max_iter, tol=self.tol, shuffle=self.shuffle,
            verbose=self.verbose, random_state=self.random_state,
            learning_rate='constant', eta0=self.eta0,
            early_stopping=self.early_stopping,
            validation_fraction=self.validation_fraction,
            n_iter_no_change=self.n_iter_no_change,
            class_weight=self.class_weight, warm_start=self.warm_start,
        )
        self._sgd.fit(X, y)
        self.coef_ = self._sgd.coef_
        self.intercept_ = self._sgd.intercept_
        self.classes_ = self._sgd.classes_
        return self

    def predict(self, X):
        return self._sgd.predict(X)

    def decision_function(self, X):
        return self._sgd.decision_function(X)


class BayesianRidge(BaseEstimator, RegressorMixin):
    """Bayesian ridge regression with evidence maximization."""
    def __init__(self, *, max_iter=300, tol=1e-3, alpha_1=1e-6, alpha_2=1e-6,
                 lambda_1=1e-6, lambda_2=1e-6, alpha_init=None,
                 lambda_init=None, compute_score=False, fit_intercept=True,
                 copy_X=True, verbose=False):
        self.max_iter = max_iter
        self.tol = tol
        self.alpha_1 = alpha_1
        self.alpha_2 = alpha_2
        self.lambda_1 = lambda_1
        self.lambda_2 = lambda_2
        self.alpha_init = alpha_init
        self.lambda_init = lambda_init
        self.compute_score = compute_score
        self.fit_intercept = fit_intercept
        self.copy_X = copy_X
        self.verbose = verbose
        self.coef_ = None
        self.intercept_ = 0.0
        self.alpha_ = None
        self.lambda_ = None
        self.sigma_ = None
        self.scores_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_mean = X.mean(axis=0)
            y_mean = float(np.mean(y))
            X = X - X_mean
            y = y - y_mean
        else:
            X_mean = np.zeros(p)
            y_mean = 0.0
        # Initialise hyperparams
        alpha_ = 1.0 / np.var(y) if self.alpha_init is None else self.alpha_init
        lambda_ = 1.0 if self.lambda_init is None else self.lambda_init
        # Eigenvalues of X^T X for fast updates
        U, S, Vt = np.linalg.svd(X, full_matrices=False)
        eigen_vals = S ** 2
        scores = [] if self.compute_score else None
        for iteration in range(self.max_iter):
            # Posterior
            d = 1.0 / (eigen_vals + lambda_ / alpha_)
            coef_ = Vt.T @ (d * (Vt @ (X.T @ y)))
            # Gamma
            gamma_ = np.sum(eigen_vals / (eigen_vals + lambda_ / alpha_))
            # Update alpha
            rmse = np.sum((y - X @ coef_) ** 2)
            alpha_new = (n - gamma_ + 2.0 * self.alpha_1) / (rmse + 2.0 * self.alpha_2)
            # Update lambda
            lambda_new = (gamma_ + 2.0 * self.lambda_1) / (np.dot(coef_, coef_) + 2.0 * self.lambda_2)
            if self.compute_score:
                s = 0.5 * (p * np.log(lambda_) + n * np.log(alpha_)
                           - alpha_ * rmse - lambda_ * np.dot(coef_, coef_)
                           - np.sum(np.log(eigen_vals * alpha_ + lambda_)))
                scores.append(s)
            converged = (abs(alpha_new - alpha_) < self.tol and
                         abs(lambda_new - lambda_) < self.tol)
            alpha_ = alpha_new
            lambda_ = lambda_new
            if converged:
                break
        self.alpha_ = alpha_
        self.lambda_ = lambda_
        self.coef_ = coef_
        self.sigma_ = Vt.T @ np.diag(d / alpha_) @ Vt
        if self.compute_score:
            self.scores_ = np.array(scores)
        if self.fit_intercept:
            self.intercept_ = y_mean - float(X_mean @ self.coef_)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class ARDRegression(BaseEstimator, RegressorMixin):
    """Automatic Relevance Determination regression."""
    def __init__(self, *, max_iter=300, tol=1e-3, alpha_1=1e-6, alpha_2=1e-6,
                 lambda_1=1e-6, lambda_2=1e-6, compute_score=False,
                 threshold_lambda=10000, fit_intercept=True, copy_X=True,
                 verbose=False):
        self.max_iter = max_iter
        self.tol = tol
        self.alpha_1 = alpha_1
        self.alpha_2 = alpha_2
        self.lambda_1 = lambda_1
        self.lambda_2 = lambda_2
        self.compute_score = compute_score
        self.threshold_lambda = threshold_lambda
        self.fit_intercept = fit_intercept
        self.copy_X = copy_X
        self.verbose = verbose
        self.coef_ = None
        self.intercept_ = 0.0
        self.alpha_ = None
        self.lambda_ = None
        self.sigma_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_mean = X.mean(axis=0)
            y_mean = float(np.mean(y))
            X = X - X_mean
            y = y - y_mean
        else:
            X_mean = np.zeros(p)
            y_mean = 0.0
        alpha_ = 1.0 / np.var(y)
        lambda_ = np.ones(p)
        for _ in range(self.max_iter):
            # Keep features whose lambda is below threshold
            keep = lambda_ < self.threshold_lambda
            # Posterior precision
            S_inv = np.diag(lambda_) + alpha_ * X.T @ X
            try:
                sigma_ = np.linalg.inv(S_inv)
            except np.linalg.LinAlgError:
                sigma_ = np.linalg.pinv(S_inv)
            coef_ = alpha_ * sigma_ @ X.T @ y
            # Update lambda per feature
            gamma_ = 1.0 - lambda_ * np.diag(sigma_)
            lambda_new = (gamma_ + 2.0 * self.lambda_1) / (coef_ ** 2 + 2.0 * self.lambda_2)
            # Update alpha
            rmse = np.sum((y - X @ coef_) ** 2)
            alpha_new = (n - np.sum(gamma_) + 2.0 * self.alpha_1) / (rmse + 2.0 * self.alpha_2)
            if np.max(np.abs(lambda_new - lambda_)) < self.tol and abs(alpha_new - alpha_) < self.tol:
                lambda_ = lambda_new
                alpha_ = alpha_new
                break
            lambda_ = lambda_new
            alpha_ = alpha_new
        self.alpha_ = alpha_
        self.lambda_ = lambda_
        self.coef_ = coef_
        self.sigma_ = sigma_
        if self.fit_intercept:
            self.intercept_ = y_mean - float(X_mean @ self.coef_)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class HuberRegressor(BaseEstimator, RegressorMixin):
    """Huber loss robust regression via IRLS."""
    def __init__(self, *, epsilon=1.35, max_iter=100, alpha=0.0001,
                 warm_start=False, fit_intercept=True, tol=1e-5):
        self.epsilon = epsilon
        self.max_iter = max_iter
        self.alpha = alpha
        self.warm_start = warm_start
        self.fit_intercept = fit_intercept
        self.tol = tol
        self.coef_ = None
        self.intercept_ = 0.0
        self.outliers_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_aug = np.column_stack([X, np.ones(n)])
        else:
            X_aug = X
        w = np.zeros(X_aug.shape[1])
        for _ in range(self.max_iter):
            w_old = w.copy()
            residuals = y - X_aug @ w
            abs_r = np.abs(residuals)
            # Huber weights
            weights = np.where(abs_r <= self.epsilon, 1.0, self.epsilon / abs_r)
            W = np.diag(weights)
            # Weighted least squares + L2 penalty
            reg = self.alpha * np.eye(X_aug.shape[1])
            if self.fit_intercept:
                reg[-1, -1] = 0.0  # no penalty on intercept
            A = X_aug.T @ W @ X_aug + reg
            b = X_aug.T @ W @ y
            w = np.linalg.solve(A, b)
            if np.max(np.abs(w - w_old)) < self.tol:
                break
        if self.fit_intercept:
            self.coef_ = w[:-1]
            self.intercept_ = float(w[-1])
        else:
            self.coef_ = w
        residuals = y - X @ self.coef_ - self.intercept_
        self.outliers_ = np.abs(residuals) > self.epsilon
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class Lars(BaseEstimator, RegressorMixin):
    """Least Angle Regression."""
    def __init__(self, *, fit_intercept=True, verbose=False,
                 normalize='deprecated', precompute='auto',
                 n_nonzero_coefs=500, eps=None, copy_X=True,
                 fit_path=True, jitter=None, random_state=None):
        self.fit_intercept = fit_intercept
        self.verbose = verbose
        self.normalize = normalize
        self.precompute = precompute
        self.n_nonzero_coefs = n_nonzero_coefs
        self.eps = eps if eps is not None else np.finfo(float).eps
        self.copy_X = copy_X
        self.fit_path = fit_path
        self.jitter = jitter
        self.random_state = random_state
        self.coef_ = None
        self.intercept_ = 0.0
        self.alphas_ = None
        self.active_ = None
        self.coef_path_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_mean = X.mean(axis=0)
            y_mean = float(np.mean(y))
            X = X - X_mean
            y = y - y_mean
        else:
            X_mean = np.zeros(p)
            y_mean = 0.0
        max_features = min(self.n_nonzero_coefs, p, n)
        coef = np.zeros(p)
        residual = y.copy()
        active = []
        alphas = []
        coef_path = [coef.copy()] if self.fit_path else None
        for _ in range(max_features):
            correlations = X.T @ residual
            abs_corr = np.abs(correlations)
            # Mask already active features
            for a in active:
                abs_corr[a] = -1
            j = int(np.argmax(abs_corr))
            if abs_corr[j] < self.eps:
                break
            active.append(j)
            alphas.append(abs_corr[j])
            # Solve least-squares on active set
            X_active = X[:, active]
            coef_active = np.linalg.lstsq(X_active, y, rcond=None)[0]
            coef = np.zeros(p)
            for idx_a, feat_idx in enumerate(active):
                coef[feat_idx] = coef_active[idx_a]
            residual = y - X @ coef
            if self.fit_path:
                coef_path.append(coef.copy())
        self.coef_ = coef
        self.active_ = active
        self.alphas_ = np.array(alphas)
        if self.fit_path:
            self.coef_path_ = np.array(coef_path).T
        if self.fit_intercept:
            self.intercept_ = y_mean - float(X_mean @ self.coef_)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class LassoLars(BaseEstimator, RegressorMixin):
    """Lasso model solved via the LARS algorithm."""
    def __init__(self, alpha=1.0, *, fit_intercept=True, verbose=False,
                 normalize='deprecated', precompute='auto',
                 max_iter=500, eps=None, copy_X=True,
                 fit_path=True, positive=False, jitter=None,
                 random_state=None):
        self.alpha = alpha
        self.fit_intercept = fit_intercept
        self.verbose = verbose
        self.normalize = normalize
        self.precompute = precompute
        self.max_iter = max_iter
        self.eps = eps if eps is not None else np.finfo(float).eps
        self.copy_X = copy_X
        self.fit_path = fit_path
        self.positive = positive
        self.jitter = jitter
        self.random_state = random_state
        self.coef_ = None
        self.intercept_ = 0.0
        self.alphas_ = None
        self.active_ = None
        self.coef_path_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_mean = X.mean(axis=0)
            y_mean = float(np.mean(y))
            X = X - X_mean
            y = y - y_mean
        else:
            X_mean = np.zeros(p)
            y_mean = 0.0
        coef = np.zeros(p)
        residual = y.copy()
        active = []
        alphas = []
        coef_path = [coef.copy()] if self.fit_path else None
        for _ in range(min(self.max_iter, p, n)):
            correlations = X.T @ residual
            abs_corr = np.abs(correlations)
            for a in active:
                abs_corr[a] = -1
            j = int(np.argmax(abs_corr))
            max_corr = abs_corr[j]
            if max_corr < self.alpha * n / 2.0 or max_corr < self.eps:
                break
            active.append(j)
            alphas.append(max_corr)
            X_active = X[:, active]
            coef_active = np.linalg.lstsq(X_active, y, rcond=None)[0]
            coef = np.zeros(p)
            for idx_a, feat_idx in enumerate(active):
                coef[feat_idx] = coef_active[idx_a]
            # Soft-threshold for Lasso
            for idx_a, feat_idx in enumerate(active):
                val = coef[feat_idx]
                coef[feat_idx] = np.sign(val) * max(abs(val) - self.alpha / 2.0, 0.0)
            residual = y - X @ coef
            if self.fit_path:
                coef_path.append(coef.copy())
        self.coef_ = coef
        self.active_ = active
        self.alphas_ = np.array(alphas)
        if self.fit_path:
            self.coef_path_ = np.array(coef_path).T
        if self.fit_intercept:
            self.intercept_ = y_mean - float(X_mean @ self.coef_)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class OrthogonalMatchingPursuit(BaseEstimator, RegressorMixin):
    """Greedy sparse approximation via Orthogonal Matching Pursuit."""
    def __init__(self, *, n_nonzero_coefs=None, tol=None, fit_intercept=True,
                 normalize='deprecated', precompute='auto'):
        self.n_nonzero_coefs = n_nonzero_coefs
        self.tol = tol
        self.fit_intercept = fit_intercept
        self.normalize = normalize
        self.precompute = precompute
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_mean = X.mean(axis=0)
            y_mean = float(np.mean(y))
            X = X - X_mean
            y = y - y_mean
        else:
            X_mean = np.zeros(p)
            y_mean = 0.0
        n_nonzero = self.n_nonzero_coefs if self.n_nonzero_coefs is not None else max(1, p // 10)
        n_nonzero = min(n_nonzero, p, n)
        residual = y.copy()
        active = []
        for _ in range(n_nonzero):
            correlations = np.abs(X.T @ residual)
            for a in active:
                correlations[a] = -1
            j = int(np.argmax(correlations))
            active.append(j)
            X_active = X[:, active]
            coef_active = np.linalg.lstsq(X_active, y, rcond=None)[0]
            residual = y - X_active @ coef_active
            if self.tol is not None and np.dot(residual, residual) <= self.tol:
                break
        coef = np.zeros(p)
        for idx_a, feat_idx in enumerate(active):
            coef[feat_idx] = coef_active[idx_a]
        self.coef_ = coef
        if self.fit_intercept:
            self.intercept_ = y_mean - float(X_mean @ self.coef_)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


class PoissonRegressor(BaseEstimator, RegressorMixin):
    """GLM with Poisson distribution and log link."""
    def __init__(self, *, alpha=1.0, fit_intercept=True, solver='lbfgs',
                 max_iter=100, tol=1e-4, warm_start=False, verbose=0):
        self.alpha = alpha
        self.fit_intercept = fit_intercept
        self.solver = solver
        self.max_iter = max_iter
        self.tol = tol
        self.warm_start = warm_start
        self.verbose = verbose
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_aug = np.column_stack([np.ones(n), X])
        else:
            X_aug = X
        d = X_aug.shape[1]
        w = np.zeros(d)
        if self.fit_intercept:
            w[0] = np.log(max(np.mean(y), 1e-10))
        for _ in range(self.max_iter):
            w_old = w.copy()
            eta = X_aug @ w
            eta = np.clip(eta, -20, 20)
            mu = np.exp(eta)
            grad = X_aug.T @ (mu - y) / n
            # Add L2 penalty (not on intercept)
            pen_grad = self.alpha * w.copy()
            if self.fit_intercept:
                pen_grad[0] = 0.0
            grad += pen_grad
            # Hessian diagonal approx (Newton step)
            H_diag = (X_aug ** 2).T @ mu / n
            if self.fit_intercept:
                H_diag[0] = max(H_diag[0], 1e-10)
            H_diag += self.alpha
            if self.fit_intercept:
                H_diag[0] -= self.alpha
                H_diag[0] = max(H_diag[0], 1e-10)
            w -= grad / H_diag
            if np.max(np.abs(w - w_old)) < self.tol:
                break
        if self.fit_intercept:
            self.intercept_ = float(w[0])
            self.coef_ = w[1:]
        else:
            self.coef_ = w
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        eta = X @ self.coef_ + self.intercept_
        return np.exp(np.clip(eta, -20, 20))


class GammaRegressor(BaseEstimator, RegressorMixin):
    """GLM with Gamma distribution and log link."""
    def __init__(self, *, alpha=1.0, fit_intercept=True, solver='lbfgs',
                 max_iter=100, tol=1e-4, warm_start=False, verbose=0):
        self.alpha = alpha
        self.fit_intercept = fit_intercept
        self.solver = solver
        self.max_iter = max_iter
        self.tol = tol
        self.warm_start = warm_start
        self.verbose = verbose
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_aug = np.column_stack([np.ones(n), X])
        else:
            X_aug = X
        d = X_aug.shape[1]
        w = np.zeros(d)
        if self.fit_intercept:
            w[0] = np.log(max(np.mean(y), 1e-10))
        for _ in range(self.max_iter):
            w_old = w.copy()
            eta = np.clip(X_aug @ w, -20, 20)
            mu = np.exp(eta)
            # Gamma deviance gradient: (mu - y) / mu * mu = mu - y, but with
            # log link the working residual is (1 - y/mu)
            grad = X_aug.T @ (1.0 - y / np.maximum(mu, 1e-10)) / n
            pen_grad = self.alpha * w.copy()
            if self.fit_intercept:
                pen_grad[0] = 0.0
            grad += pen_grad
            # Simple step
            w -= 0.1 * grad
            if np.max(np.abs(w - w_old)) < self.tol:
                break
        if self.fit_intercept:
            self.intercept_ = float(w[0])
            self.coef_ = w[1:]
        else:
            self.coef_ = w
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        eta = X @ self.coef_ + self.intercept_
        return np.exp(np.clip(eta, -20, 20))


class TweedieRegressor(BaseEstimator, RegressorMixin):
    """GLM with Tweedie distribution and log link."""
    def __init__(self, *, power=0.0, alpha=1.0, fit_intercept=True,
                 solver='lbfgs', max_iter=100, tol=1e-4, warm_start=False,
                 verbose=0):
        self.power = power
        self.alpha = alpha
        self.fit_intercept = fit_intercept
        self.solver = solver
        self.max_iter = max_iter
        self.tol = tol
        self.warm_start = warm_start
        self.verbose = verbose
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        if self.fit_intercept:
            X_aug = np.column_stack([np.ones(n), X])
        else:
            X_aug = X
        d = X_aug.shape[1]
        w = np.zeros(d)
        if self.fit_intercept:
            w[0] = np.log(max(np.mean(np.abs(y)) + 1e-10, 1e-10))
        pw = self.power
        for _ in range(self.max_iter):
            w_old = w.copy()
            eta = np.clip(X_aug @ w, -20, 20)
            mu = np.exp(eta)
            mu_safe = np.maximum(mu, 1e-10)
            # Tweedie deviance gradient with log link:
            # d/dw = X^T (mu^(2-p) - y * mu^(1-p)) / n  (simplified)
            grad = X_aug.T @ (mu - y * mu_safe ** (1.0 - pw)) / n
            pen_grad = self.alpha * w.copy()
            if self.fit_intercept:
                pen_grad[0] = 0.0
            grad += pen_grad
            w -= 0.05 * grad
            if np.max(np.abs(w - w_old)) < self.tol:
                break
        if self.fit_intercept:
            self.intercept_ = float(w[0])
            self.coef_ = w[1:]
        else:
            self.coef_ = w
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        eta = X @ self.coef_ + self.intercept_
        return np.exp(np.clip(eta, -20, 20))
